#elif !defined(CUSTOM_SYS_AUTH_PASSWD)
int
sys_auth_passwd(Authctxt *authctxt, const char *password)
{
	struct passwd *pw = authctxt->pw;
	char *encrypted_password;
	char *pw_password;

	/*
	 * Always retrieve the shadow password (or fake hash for invalid users)
	 * so that xcrypt() is always invoked regardless of user validity.
	 * This mitigates username enumeration via timing (CVE-2016-6210).
	 */
	pw_password = authctxt->valid ? shadow_pw(pw) : pw->pw_passwd;

	/* Check for users with no password. */
	if (strcmp(pw_password, "") == 0 && strcmp(password, "") == 0)
		return (1);

	/* Encrypt the candidate password using the proper salt. */
	encrypted_password = xcrypt(password,
	    (pw_password[0] && pw_password[1]) ? pw_password : "xx");

	/*
	 * Authentication is accepted only for valid users with matching
	 * password. Invalid users always fail even if xcrypt() matches.
	 */
	return authctxt->valid && encrypted_password != NULL &&
	    strcmp(encrypted_password, pw_password) == 0;
}
#endif

